mapper.select:
SELECT al.id ,al.security_code ,al.security_short_name ,al.security_type ,al.adjust_type ,al.adjust_mode ,CASE WHEN p.parent_id IS NOT NULL THEN CONCAT(pp.pool_name, '/', p.pool_name) ELSE p.pool_name END AS target_pool_path ,al.pool_type ,al.audit_status ,al.adjuster_name ,al.adjust_reason ,al.submit_time FROM ip_adjust_log al LEFT JOIN ip_investment_pool p ON p.id = al.target_pool_id AND p.is_deleted = 0 LEFT JOIN ip_investment_pool pp ON pp.id = p.parent_id AND pp.is_deleted = 0 LEFT JOIN sirm_securityinfo sb ON sb.s_info_code = al.security_code
al.is_deleted = 0
AND al.target_pool_id IN
#{id}
AND al.security_code LIKE CONCAT('%', #{securityCode}, '%')
AND al.security_type = #{securityType}
AND (CASE WHEN sb.b_info_maturitydate IS NOT NULL AND sb.b_info_maturitydate < DATE_FORMAT(NOW(), '%Y-%m-%d') THEN '到期' ELSE '存续' END) = #{securityStatus}
AND al.submit_time >= #{adjustTimeStart}
AND al.submit_time <= CONCAT(#{adjustTimeEnd}, ' 23:59:59')
AND al.adjuster_name LIKE CONCAT('%', #{adjusterName}, '%')
AND sb.b_info_issuer LIKE CONCAT('%', #{issuer}, '%')
AND al.adjust_mode = #{adjustMode}
AND al.audit_status = #{auditStatus}
AND al.adjuster_id = #{currentUserId}
ORDER BY al.submit_time DESC ,al.id DESC
